import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { ElectionService } from '../../services/election.service';
import { Election } from '../../models/models';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit {
  elections: Election[] = [];
  loading = true;
  error = '';
  currentUser: any;

  constructor(
    private authService: AuthService,
    private electionService: ElectionService,
    private router: Router
  ) {
    this.currentUser = this.authService.currentUserValue;
  }

  ngOnInit(): void {
    this.loadElections();
  }

  loadElections(): void {
    this.loading = true;
    this.electionService.getAllElections()
      .subscribe({
        next: (response) => {
          if (response.success) {
            this.elections = response.data;
          }
          this.loading = false;
        },
        error: (error) => {
          this.error = 'Failed to load elections';
          this.loading = false;
        }
      });
  }

  get activeElections(): Election[] {
    return this.elections.filter(e => e.is_active);
  }

  get upcomingElections(): Election[] {
    return this.elections.filter(e => !e.is_active);
  }

  viewElection(electionId: number): void {
    this.router.navigate(['/elections', electionId]);
  }

  get isAdmin(): boolean {
    return this.authService.isAdmin;
  }
}
<div class="home-container">
  <app-navbar></app-navbar>

  <div class="content">
    <div class="header">
      <h1>Welcome, {{ currentUser?.username }}!</h1>
      <p class="subtitle">Choose an election to participate in</p>
    </div>

    <div class="alert alert-danger" *ngIf="error">
      {{ error }}
    </div>

    <div class="loading" *ngIf="loading">
      <div class="spinner-large"></div>
      <p>Loading elections...</p>
    </div>

    <div *ngIf="!loading">
      <!-- Active Elections -->
      <div class="section" *ngIf="activeElections.length > 0">
        <h2>Active Elections</h2>
        <div class="elections-grid">
          <div 
            class="election-card active" 
            *ngFor="let election of activeElections"
            (click)="viewElection(election.id)"
          >
            <div class="election-badge">ACTIVE</div>
            <h3>{{ election.title }}</h3>
            <p class="description">{{ election.description || 'No description available' }}</p>
            <div class="election-stats">
              <div class="stat">
                <span class="stat-value">{{ election.position_count || 0 }}</span>
                <span class="stat-label">Positions</span>
              </div>
              <div class="stat">
                <span class="stat-value">{{ election.total_votes || 0 }}</span>
                <span class="stat-label">Votes Cast</span>
              </div>
            </div>
            <button class="btn btn-primary">Vote Now</button>
          </div>
        </div>
      </div>

      <!-- Upcoming Elections -->
      <div class="section" *ngIf="upcomingElections.length > 0">
        <h2>Upcoming Elections</h2>
        <div class="elections-grid">
          <div 
            class="election-card" 
            *ngFor="let election of upcomingElections"
            (click)="viewElection(election.id)"
          >
            <div class="election-badge upcoming">UPCOMING</div>
            <h3>{{ election.title }}</h3>
            <p class="description">{{ election.description || 'No description available' }}</p>
            <div class="election-stats">
              <div class="stat">
                <span class="stat-value">{{ election.position_count || 0 }}</span>
                <span class="stat-label">Positions</span>
              </div>
            </div>
            <button class="btn btn-secondary">View Details</button>
          </div>
        </div>
      </div>

      <!-- No Elections -->
      <div class="empty-state" *ngIf="elections.length === 0">
        <div class="empty-icon">🗳️</div>
        <h3>No Elections Available</h3>
        <p>There are currently no elections to display.</p>
        <button 
          *ngIf="isAdmin" 
          class="btn btn-primary"
          routerLink="/admin/elections/create"
        >
          Create New Election
        </button>
      </div>
    </div>
  </div>
</div>
